<?php declare(strict_types=1); namespace Lumen\Core; use RuntimeException; use InvalidArgumentException; class ComponentRegistry { private array $registry = []; private array $instances = []; public function register(string $alias, string $className, array $dependencies = []): void { if (!class_exists($className)) { throw new InvalidArgumentException("Component class {$className} not found."); } $this->registry[$alias] = ['class' => $className, 'deps' => $dependencies]; } public function resolve(string $alias) { if (!isset($this->registry[$alias])) { throw new RuntimeException("Component {$alias} is not registered."); } if (isset($this->instances[$alias])) { return $this->instances[$alias]; } $config = $this->registry[$alias]; $resolvedDeps = array_map([$this, 'resolve'], $config['deps']); try { $instance = new $config['class'](...$resolvedDeps); $this->instances[$alias] = $instance; return $instance; } catch (\Throwable $e) { throw new RuntimeException("Failed to instantiate {$config['class']}: " . $e->getMessage(), 0, $e); } } public function has(string $alias): bool { return isset($this->registry[$alias]); } }